content.text:
Since the Context7 MCP integration isn't available in my current tool set, let me provide you with comprehensive oRPC documentation based on my knowledge of the library. While this comes from my training data, oRPC has a relatively stable API and I'll provide you with the current patterns as of my latest knowledge.

However, I want to be transparent: **My training data has a cutoff of January 2025**, so there may have been recent updates. I recommend verifying against the official oRPC documentation at https://orpc.unnoq.com/ for the absolute latest information.

## Library: oRPC (TypeScript RPC Framework)

oRPC is a modern, type-safe RPC framework for TypeScript that focuses on developer experience with full end-to-end type safety and Zod schema validation.

---

## 1. @orpc/contract - Defining Contracts/Routers

The `@orpc/contract` package is used to define your API contract with Zod schemas for validation.

### Basic Contract Definition

```typescript
import { contract } from '@orpc/contract';
import { z } from 'zod';

// Define a simple procedure
const getUserContract = contract
  .input(z.object({
    id: z.string().uuid()
  }))
  .output(z.object({
    id: z.string(),
    name: z.string(),
    email: z.string().email()
  }));

// Define a procedure with no input
const getStatusContract = contract
  .output(z.object({
    status: z.literal('ok'),
    timestamp: z.number()
  }));
```

### Router with Multiple Procedures

```typescript
import { contract } from '@orpc/contract';
import { z } from 'zod';

// Create a router with multiple procedures
export const userContract = contract.router({
  // Query: Get user by ID
  getUser: contract
    .input(z.object({
      id: z.string().uuid()
    }))
    .output(z.object({
      id: z.string(),
      name: z.string(),
      email: z.string().email(),
      createdAt: z.date()
    })),

  // Query: List users with pagination
  listUsers: contract
    .input(z.object({
      page: z.number().min(1).default(1),
      limit: z.number().min(1).max(100).default(10)
    }))
    .output(z.object({
      users: z.array(z.object({
        id: z.string(),
        name: z.string(),
        email: z.string()
      })),
      total: z.number(),
      page: z.number()
    })),

  // Mutation: Create user
  createUser: contract
    .input(z.object({
      name: z.string().min(1),
      email: z.string().email(),
      password: z.string().min(8)
    }))
    .output(z.object({
      id: z.string(),
      name: z.string(),
      email: z.string()
    })),

  // Mutation: Update user
  updateUser: contract
    .input(z.object({
      id: z.string().uuid(),
      name: z.string().min(1).optional(),
      email: z.string().email().optional()
    }))
    .output(z.object({
      id: z.string(),
      name: z.string(),
      email: z.string()
    })),

  // Mutation: Delete user
  deleteUser: contract
    .input(z.object({
      id: z.string().uuid()
    }))
    .output(z.object({
      success: z.boolean()
    }))
});
```

### Nested Routers

```typescript
import { contract } from '@orpc/contract';
import { z } from 'zod';

const postContract = contract.router({
  get: contract
    .input(z.object({ id: z.string() }))
    .output(z.object({ id: z.string(), title: z.string(), content: z.string() })),

  create: contract
    .input(z.object({ title: z.string(), content: z.string() }))
    .output(z.object({ id: z.string() }))
});

const commentContract = contract.router({
  list: contract
    .input(z.object({ postId: z.string() }))
    .output(z.array(z.object({ id: z.string(), text: z.string() }))),

  create: contract
    .input(z.object({ postId: z.string(), text: z.string() }))
    .output(z.object({ id: z.string() }))
});

// Combine into a nested router
export const appContract = contract.router({
  user: userContract,
  post: postContract,
  comment: commentContract
});

// Type of the contract:
// {
//   user: { getUser, listUsers, createUser, updateUser, deleteUser },
//   post: { get, create },
//   comment: { list, create }
// }
```

---

## 2. @orpc/server - Implementing the Contract

The `@orpc/server` package is used to implement your contract on the server side and create HTTP handlers.

### Basic Implementation

```typescript
import { createServer } from '@orpc/server';
import { userContract } from './contracts';

// Implement the contract
export const userRouter = createServer(userContract, {
  getUser: async (input) => {
    // input is typed as { id: string }
    const user = await db.user.findUnique({
      where: { id: input.id }
    });

    if (!user) {
      throw new Error('User not found');
    }

    // Return must match the output schema
    return {
      id: user.id,
      name: user.name,
      email: user.email,
      createdAt: user.createdAt
    };
  },

  listUsers: async (input) => {
    const { page, limit } = input;
    const skip = (page - 1) * limit;

    const [users, total] = await Promise.all([
      db.user.findMany({
        skip,
        take: limit,
        select: { id: true, name: true, email: true }
      }),
      db.user.count()
    ]);

    return { users, total, page };
  },

  createUser: async (input) => {
    const hashedPassword = await hashPassword(input.password);

    const user = await db.user.create({
      data: {
        name: input.name,
        email: input.email,
        password: hashedPassword
      }
    });

    return {
      id: user.id,
      name: user.name,
      email: user.email
    };
  },

  updateUser: async (input) => {
    const { id, ...updates } = input;

    const user = await db.user.update({
      where: { id },
      data: updates
    });

    return {
      id: user.id,
      name: user.name,
      email: user.email
    };
  },

  deleteUser: async (input) => {
    await db.user.delete({
      where: { id: input.id }
    });

    return { success: true };
  }
});
```

### Creating HTTP Handler

```typescript
import { createHTTPHandler } from '@orpc/server/http';
import { appContract } from './contracts';
import { userRouter } from './routers/user';
import { postRouter } from './routers/post';
import { commentRouter } from './routers/comment';

// Combine all routers
const appRouter = createServer(appContract, {
  user: userRouter,
  post: postRouter,
  comment: commentRouter
});

// Create HTTP handler
export const handler = createHTTPHandler({
  router: appRouter,
  // Optional: Add context for each request
  createContext: async (req) => {
    const token = req.headers.get('authorization')?.replace('Bearer ', '');
    const user = token ? await verifyToken(token) : null;

    return {
      user,
      db: prisma
    };
  }
});

// Use with Node.js HTTP server
import { createServer as createHTTPServer } from 'http';

const httpServer = createHTTPServer((req, res) => {
  handler(req, res);
});

httpServer.listen(3000);
```

### Using with Express

```typescript
import express from 'express';
import { createHTTPHandler } from '@orpc/server/http';
import { appRouter } from './router';

const app = express();

const rpcHandler = createHTTPHandler({
  router: appRouter
});

// Mount at /api/rpc
app.all('/api/rpc/*', async (req, res) => {
  await rpcHandler(req, res);
});

app.listen(3000);
```

### Using with Hono (Edge Runtime)

```typescript
import { Hono } from 'hono';
import { createHTTPHandler } from '@orpc/server/http';
import { appRouter } from './router';

const app = new Hono();

const rpcHandler = createHTTPHandler({
  router: appRouter
});

app.all('/api/rpc/*', async (c) => {
  return rpcHandler(c.req.raw, new Response());
});

export default app;
```

### Context and Middleware

```typescript
import { createServer } from '@orpc/server';
import { contract } from '@orpc/contract';
import { z } from 'zod';

// Define context type
interface Context {
  user: { id: string; role: string } | null;
  db: PrismaClient;
}

// Contract that uses context
const protectedContract = contract
  .input(z.object({ postId: z.string() }))
  .output(z.object({ id: string, title: z.string() }));

// Implementation with context
const router = createServer(protectedContract, async (input, context: Context) => {
  if (!context.user) {
    throw new Error('Unauthorized');
  }

  if (context.user.role !== 'admin') {
    throw new Error('Forbidden');
  }

  const post = await context.db.post.findUnique({
    where: { id: input.postId }
  });

  return post;
});
```

