### Optimistic Updates

```typescript
'use client';

import { orpc } from '@/lib/orpc-client';
import { useQueryClient } from '@tanstack/react-query';

export function UpdateUserButton({ userId }: { userId: string }) {
  const queryClient = useQueryClient();

  const updateUser = orpc.user.updateUser.useMutation({
    // Optimistic update
    onMutate: async (variables) => {
      // Cancel outgoing refetches
      await queryClient.cancelQueries({ 
        queryKey: ['user', 'getUser', { id: variables.id }] 
      });

      // Snapshot previous value
      const previous = queryClient.getQueryData([
        'user', 'getUser', { id: variables.id }
      ]);

      // Optimistically update
      queryClient.setQueryData(
        ['user', 'getUser', { id: variables.id }],
        (old: any) => ({
          ...old,
          ...variables
        })
      );

      return { previous };
    },

    // On error, rollback
    onError: (err, variables, context) => {
      if (context?.previous) {
        queryClient.setQueryData(
          ['user', 'getUser', { id: variables.id }],
          context.previous
        );
      }
    },

    // Always refetch after error or success
    onSettled: (data, error, variables) => {
      queryClient.invalidateQueries({
        queryKey: ['user', 'getUser', { id: variables.id }]
      });
    }
  });

  return (
    <button onClick={() => updateUser.mutate({ 
      id: userId, 
      name: 'Updated Name' 
    })}>
      Update User
    </button>
  );
}
```

### Infinite Queries

```typescript
'use client';

import { orpc } from '@/lib/orpc-client';

export function InfiniteUserList() {
  const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
    isLoading
  } = orpc.user.listUsers.useInfiniteQuery(
    {
      limit: 20
    },
    {
      getNextPageParam: (lastPage, allPages) => {
        const nextPage = allPages.length + 1;
        return nextPage <= Math.ceil(lastPage.total / 20) 
          ? nextPage 
          : undefined;
      }
    }
  );

  if (isLoading) return <div>Loading...</div>;

  return (
    <div>
      {data?.pages.map((page, i) => (
        <div key={i}>
          {page.users.map(user => (
            <div key={user.id}>
              {user.name} - {user.email}
            </div>
          ))}
        </div>
      ))}

      {hasNextPage && (
        <button
          onClick={() => fetchNextPage()}
          disabled={isFetchingNextPage}
        >
          {isFetchingNextPage ? 'Loading more...' : 'Load More'}
        </button>
      )}
    </div>
  );
}
```

