    id: userId
  });

  if (isLoading) return <div>Loading...</div>;
  if (error) return <div>Error: {error.message}</div>;
  if (!data) return null;

  return (
    <div>
      <h1>{data.name}</h1>
      <p>{data.email}</p>
      <p>Created: {data.createdAt.toLocaleDateString()}</p>
    </div>
  );
}
```

### Using Mutations

```typescript
'use client';

import { orpc } from '@/lib/orpc-client';
import { useQueryClient } from '@tanstack/react-query';

export function CreateUserForm() {
  const queryClient = useQueryClient();

  // useMutation hook
  const createUser = orpc.user.createUser.useMutation({
    onSuccess: (newUser) => {
      // Invalidate and refetch users list
      queryClient.invalidateQueries({
        queryKey: ['user', 'listUsers']
      });

      console.log('Created user:', newUser);
    },
    onError: (error) => {
      console.error('Failed to create user:', error);
    }
  });

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    createUser.mutate({
      name: formData.get('name') as string,
      email: formData.get('email') as string,
      password: formData.get('password') as string
    });
  };

  return (
    <form onSubmit={handleSubmit}>
      <input name="name" placeholder="Name" required />
      <input name="email" type="email" placeholder="Email" required />
      <input name="password" type="password" placeholder="Password" required />

      <button 
        type="submit" 
        disabled={createUser.isPending}
      >
        {createUser.isPending ? 'Creating...' : 'Create User'}
      </button>

      {createUser.error && (
        <p className="error">{createUser.error.message}</p>
      )}
    </form>
  );
}
```

### List with Pagination

```typescript
'use client';

import { orpc } from '@/lib/orpc-client';
import { useState } from 'react';

export function UserList() {
  const [page, setPage] = useState(1);

  const { data, isLoading, error, isFetching } = orpc.user.listUsers.useQuery({
    page,
    limit: 10
  });

  if (isLoading) return <div>Loading...</div>;
  if (error) return <div>Error: {error.message}</div>;
  if (!data) return null;

  return (
    <div>
      <h2>Users ({data.total})</h2>

      {isFetching && <div className="loading-indicator">Updating...</div>}

      <ul>
        {data.users.map(user => (
          <li key={user.id}>
            {user.name} - {user.email}
          </li>
        ))}
      </ul>

      <div className="pagination">
        <button 
          onClick={() => setPage(p => Math.max(1, p - 1))}
          disabled={page === 1}
        >
          Previous
        </button>

        <span>Page {page} of {Math.ceil(data.total / 10)}</span>

        <button 
          onClick={() => setPage(p => p + 1)}
          disabled={page >= Math.ceil(data.total / 10)}
        >
          Next
        </button>
      </div>
    </div>
  );
}
```

### Optimistic Updates

```typescript
'use client';

import { orpc } from '@/lib/orpc-client';
import { useQueryClient } from '@tanstack/react-query';

export function UpdateUserButton({ userId }: { userId: string }) {
  const queryClient = useQueryClient();

  const updateUser = orpc.user.updateUser.useMutation({
    // Optimistic update
    onMutate: async (variables) => {
      // Cancel outgoing refetches
      await queryClient.cancelQueries({ 
        queryKey: ['user', 'getUser', { id: variables.id }] 
      });

      // Snapshot previous value
      const previous = queryClient.getQueryData([
        'user', 'getUser', { id: variables.id }
      ]);

      // Optimistically update
      queryClient.setQueryData(
        ['user', 'getUser', { id: variables.id }],
        (old: any) => ({
          ...old,
          ...variables
        })
      );

      return { previous };
    },

    // On error, rollback
    onError: (err, variables, context) => {
      if (context?.previous) {
        queryClient.setQueryData(
          ['user', 'getUser', { id: variables.id }],
          context.previous
        );
      }
    },

    // Always refetch after error or success
    onSettled: (data, error, variables) => {
      queryClient.invalidateQueries({
        queryKey: ['user', 'getUser', { id: variables.id }]
      });
    }
  });

  return (
    <button onClick={() => updateUser.mutate({ 
      id: userId, 
      name: 'Updated Name' 
    })}>
      Update User
    </button>
  );
}
```

### Infinite Queries

```typescript
'use client';

import { orpc } from '@/lib/orpc-client';

export function InfiniteUserList() {
  const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
    isLoading
  } = orpc.user.listUsers.useInfiniteQuery(
    {
      limit: 20
    },
    {
      getNextPageParam: (lastPage, allPages) => {
        const nextPage = allPages.length + 1;
        return nextPage <= Math.ceil(lastPage.total / 20) 
          ? nextPage 
          : undefined;
      }
    }
  );

  if (isLoading) return <div>Loading...</div>;

  return (
    <div>
      {data?.pages.map((page, i) => (
        <div key={i}>
          {page.users.map(user => (
            <div key={user.id}>
              {user.name} - {user.email}
            </div>
          ))}
        </div>
      ))}

      {hasNextPage && (
        <button
          onClick={() => fetchNextPage()}
          disabled={isFetchingNextPage}
        >
          {isFetchingNextPage ? 'Loading more...' : 'Load More'}
        </button>
      )}
    </div>
  );
}
```

---

## Monorepo Setup Example

Here's how to structure oRPC in a monorepo:

```
/packages/
  /api-contract/          # Shared contract
    package.json
    src/
      index.ts            # Export contracts
      user.contract.ts
      post.contract.ts

  /api-server/            # Server implementation
    package.json
    src/
      index.ts            # HTTP handler
      routers/
        user.router.ts
        post.router.ts

  /api-client/            # Client package
    package.json
    src/
      index.ts            # Export typed client

/apps/
  /web/                   # Next.js app
    package.json
    app/
      providers.tsx       # TanStack Query setup
```

### packages/api-contract/package.json

```json
{
  "name": "@acme/api-contract",
  "version": "0.0.0",
  "main": "./src/index.ts",
  "types": "./src/index.ts",
  "dependencies": {
    "@orpc/contract": "^0.x.x",
    "zod": "^3.22.0"
  }
}
```

### packages/api-server/package.json

```json
{
  "name": "@acme/api-server",
  "version": "0.0.0",
  "main": "./src/index.ts",
  "dependencies": {
    "@acme/api-contract": "workspace:*",
    "@orpc/server": "^0.x.x",
    "hono": "^4.x.x"
  }
}
```

### packages/api-client/package.json

```json
{
  "name": "@acme/api-client",
  "version": "0.0.0",
  "main": "./src/index.ts",
  "dependencies": {
    "@acme/api-contract": "workspace:*",
    "@orpc/client": "^0.x.x",
    "@orpc/tanstack-query": "^0.x.x",
    "@tanstack/react-query": "^5.x.x"
  }
}
```

---

## Summary

**Key Points:**

1. **@orpc/contract**: Define your API shape with Zod schemas using `contract.input()` and `contract.output()`, combine into routers with `contract.router()`

2. **@orpc/server**: Implement contracts with `createServer()`, create HTTP handlers with `createHTTPHandler()`, works with any Node.js HTTP framework

3. **@orpc/client**: Type-safe client created with `createClient<typeof contract>()`, automatically typed based on your contract

4. **@orpc/tanstack-query**: React hooks like `useQuery()` and `useMutation()` that are automatically generated from your contract

5. **Monorepo Benefits**: Share the contract package between server and client for end-to-end type safety

The main advantage of oRPC is complete type safety from contract definition through server implementation to client usage, with automatic runtime validation via Zod schemas.

**Important Note**: Please verify these patterns against the official documentation at https://orpc.unnoq.com/ as there may have been API changes since my training cutoff in January 2025.

