# Complete RPCLink Setup for oRPC Client

## Basic RPCLink Configuration

```typescript
import { onError } from '@orpc/client'
import { RPCLink } from '@orpc/client/fetch'
import { createORPCClient } from '@orpc/client'
import type { RouterClient } from '@orpc/server'

const link = new RPCLink({
  url: 'http://localhost:3000/rpc',
  headers: () => ({
    'x-api-key': 'my-api-key'
  }),
  fetch: (request, init) => {
    return globalThis.fetch(request, {
      ...init,
      credentials: 'include',
    })
  },
  interceptors: [
    onError((error) => {
      console.error(error)
    })
  ],
})

export const client = createORPCClient(link)
```

## With Client Context

```typescript
import { router } from './shared/planet'
import { RouterClient } from '@orpc/server'
import { createORPCClient } from '@orpc/client'
import { RPCLink } from '@orpc/client/fetch'

interface ClientContext {
  something?: string
}

const link = new RPCLink<ClientContext>({
  url: 'http://localhost:3000/rpc',
  headers: async ({ context }) => ({
    'x-api-key': context?.something ?? ''
  })
})

const client: RouterClient<typeof router, ClientContext> = 
  createORPCClient(link)

const result = await client.planet.list(
  { limit: 10 },
  { context: { something: 'value' } }
)
```

## With Custom HTTP Methods

```typescript
const link = new RPCLink<ClientContext>({
  url: 'http://localhost:3000/rpc',
  method: ({ context }, path) => {
    if (context?.cache) return 'GET'
    if (typeof window === 'undefined') return 'GET'
    if (path.at(-1)?.match(/^(?:get|find|list|search)(?:[A-Z].*)?$/)) {
      return 'GET'
    }
    return 'POST'
  },
  fetch: (request, init, { context }) => 
    globalThis.fetch(request, {
      ...init,
      cache: context?.cache,
    }),
})
```

## With Lazy URL

```typescript
const link = new RPCLink({
  url: () => {
    if (typeof window === 'undefined') {
      throw new Error('RPCLink requires browser environment')
    }
    return `${window.location.origin}/rpc`
  },
})
```

The framework requires an RPCHandler server setup before clients can function.

